class SecureRotatingFileHandler(logging.handlers.RotatingFileHandler):
    def __init__(self, filename, mode='a', maxBytes=0, backupCount=0, 
                 encoding=None, delay=False, permissions=0o640):
        self.permissions = permissions
        super().__init__(filename, mode, maxBytes, backupCount, encoding, delay)
        self._set_permissions()
    
    def _set_permissions(self):
        if os.path.exists(self.baseFilename):
            os.chmod(self.baseFilename, self.permissions)
    
    def _open(self):
        stream = super()._open()
        self._set_permissions()
        return stream
    
    def doRollover(self):
        super().doRollover()
        self._set_permissions()
        for i in range(1, self.backupCount + 1):
            backup_file = f"{self.baseFilename}.{i}"
            if os.path.exists(backup_file):
                os.chmod(backup_file, self.permissions)


