class MultiFileLogger:
    def __init__(self, app_name='MyApp', log_dir='logs', 
                 max_bytes=10*1024*1024, backup_count=5,
                 log_permissions=0o640):
        self.app_name = app_name
        self.log_dir = Path(log_dir)
        self.max_bytes = max_bytes
        self.backup_count = backup_count
        self.log_permissions = log_permissions
        
        self._setup_log_directory()
        self.loggers = {}
        self._configure_loggers()
    
    def _setup_log_directory(self):
        self.log_dir.mkdir(parents=True, exist_ok=True)
        os.chmod(self.log_dir, 0o750)
    
    def _configure_loggers(self):
        log_configs = {
            'main': logging.INFO,
            'error': logging.ERROR,
            'debug': logging.DEBUG
        }
        
        for log_type, level in log_configs.items():
            logger_name = f'{self.app_name}.{log_type}'
            logger = logging.getLogger(logger_name)
            logger.setLevel(logging.DEBUG)
            logger.handlers.clear()
            logger.propagate = False
            
            log_file = self.log_dir / f'{self.app_name}_{log_type}.log'
            
            file_handler = SecureRotatingFileHandler(
                filename=str(log_file),
                maxBytes=self.max_bytes,
                backupCount=self.backup_count,
                permissions=self.log_permissions
            )
            file_handler.setLevel(level)
            
            formatter = logging.Formatter(
                '%(asctime)s - %(name)s - %(levelname)s - %(filename)s:%(lineno)d - %(message)s',
                datefmt='%Y-%m-%d %H:%M:%S'
            )
            file_handler.setFormatter(formatter)
            
            logger.addHandler(file_handler)
            
            if log_type == 'main':
                console_handler = logging.StreamHandler()
                console_handler.setLevel(logging.INFO)
                console_handler.setFormatter(formatter)
                logger.addHandler(console_handler)
            
            self.loggers[log_type] = logger
    
    def debug(self, message):
        self.loggers['debug'].debug(message)
        self.loggers['main'].debug(message)
    
    def info(self, message):
        self.loggers['main'].info(message)
    
    def warning(self, message):
        self.loggers['main'].warning(message)
    
    def error(self, message):
        self.loggers['error'].error(message)
        self.loggers['main'].error(message)
    
    def critical(self, message):
        self.loggers['error'].critical(message)
        self.loggers['main'].critical(message)
    
    def exception(self, message):
        self.loggers['error'].exception(message)
        self.loggers['main'].exception(message)


